#include "pch.h"
#include "ActivationTests.h"
#include "XamlTailored.h"

using namespace Microsoft::UI::Xaml::Tests::Common;
using namespace test_infra;
using namespace WEX::Common;

namespace Microsoft { namespace UI { namespace Xaml { namespace Tests { namespace Activation {

    bool ActivationTests::ClassSetup()
    {
        CommonTestSetupHelper::CommonTestClassSetup();
        return true;
    }
    
    // File generated for testing is BuildOutput\obj\<x86chk>\MergedWinMD\private\ActivationTests.g.cpp
    // generated by GenerateWinRTClassRegistrations.cs
    void ActivationTests::VerifyCanActivateTypes()
    {
        // We'll check to make sure that all types in our DLLs that are supposed to be activatable actually are.
#include "ActivationTests.g.cpp"
        
        // We'll also make sure that all of the expected lifted XAML DLLs were loaded, and that no system XAML DLLs were loaded.
        VERIFY_IS_NOT_NULL(GetModuleHandle(L"Microsoft.UI.Xaml.dll"));
        VERIFY_IS_NOT_NULL(GetModuleHandle(L"Microsoft.UI.Xaml.Phone.dll"));
        VERIFY_IS_NOT_NULL(GetModuleHandle(L"Microsoft.UI.Xaml.Controls.dll"));
        VERIFY_IS_NOT_NULL(GetModuleHandle(L"WinUIEdit.dll"));
        VERIFY_IS_NOT_NULL(GetModuleHandle(L"Microsoft.Web.WebView2.Core.dll"));
        VERIFY_IS_NULL(GetModuleHandle(L"Windows.UI.Xaml.dll"));
        VERIFY_IS_NULL(GetModuleHandle(L"Windows.UI.Xaml.Phone.dll"));
        VERIFY_IS_NULL(GetModuleHandle(L"Windows.UI.Xaml.Controls.dll"));
        VERIFY_IS_NULL(GetModuleHandle(L"msftedit.dll"));
    }
    
} } } } } // Microsoft::UI::Xaml::Tests::Activation
